const updateAgentFields = `-- name: UpdateAgentFields :one
UPDATE agents SET
    name = $1,
    slug = $2,
    auto_fix = $3,
    updated_at = now()
WHERE id = $4
RETURNING id, user_id, slug, name, description, status, upgrade_status, auto_fix, build_provider_id, build_model, exec_provider_id, exec_model, stt_provider_id, stt_model, vision_provider_id, vision_model, tts_provider_id, tts_model, image_gen_provider_id, image_gen_model, embedding_provider_id, embedding_model, search_provider_id, search_model, source_ref, image_ref, db_schema, db_password, sdk_version, config, instructions, error_message, created_at, updated_at, allow_non_member_mcp, allow_public_mcp, tools_hash, emoji, allow_oauth_mcp_prompt, allow_public_mcp_prompt, git_remote_url, git_credential_id, git_default_branch, git_webhook_secret, git_last_synced_ref
`

type UpdateAgentFieldsParams struct {
	Name    string      `json:"name"`
	Slug    string      `json:"slug"`
	AutoFix bool        `json:"auto_fix"`
	ID      pgtype.UUID `json:"id"`
}

// Caller resolves each value (keep-existing when the request omits it)
// before calling, so this is an unconditional set. slug uniqueness is
// enforced by the agents.slug UNIQUE constraint — a collision surfaces
// as a duplicate-key error the handler maps to 409.
func (q *Queries) UpdateAgentFields(ctx context.Context, arg UpdateAgentFieldsParams) (Agent, error) {
	row := q.db.QueryRow(ctx, updateAgentFields,
		arg.Name,
		arg.Slug,
		arg.AutoFix,
		arg.ID,
	)
	var i Agent
	err := row.Scan(
		&i.ID,
		&i.UserID,
		&i.Slug,
		&i.Name,
		&i.Description,
		&i.Status,
		&i.UpgradeStatus,
		&i.AutoFix,
		&i.BuildProviderID,
		&i.BuildModel,
		&i.ExecProviderID,
		&i.ExecModel,
		&i.SttProviderID,
		&i.SttModel,
		&i.VisionProviderID,
		&i.VisionModel,
		&i.TtsProviderID,
		&i.TtsModel,
		&i.ImageGenProviderID,
		&i.ImageGenModel,
		&i.EmbeddingProviderID,
		&i.EmbeddingModel,
		&i.SearchProviderID,
		&i.SearchModel,
		&i.SourceRef,
		&i.ImageRef,
		&i.DbSchema,
		&i.DbPassword,
		&i.SdkVersion,
		&i.Config,
		&i.Instructions,
		&i.ErrorMessage,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.AllowNonMemberMcp,
		&i.AllowPublicMcp,
		&i.ToolsHash,
		&i.Emoji,
		&i.AllowOauthMcpPrompt,
		&i.AllowPublicMcpPrompt,
		&i.GitRemoteUrl,
		&i.GitCredentialID,
		&i.GitDefaultBranch,
		&i.GitWebhookSecret,
		&i.GitLastSyncedRef,
	)
	return i, err
}

